// Combine all data sources into single array
const salesforceData = $input.all()
const filtered = salesforceData.filter(n => n.json.objectType !== undefined)
const cases = filtered.map(n => ({
  ...n.json,
  _source: 'salesforce',
  _sourceId: n.json.Id || n.json.CaseNumber
}))

// Limit to most recent 10,000 records
const combined = cases.slice(0, 10000)

return combined.map(d => ({ json: d }));

// Remove PII from each record
const records = $input.all();

// PII patterns
const patterns = [
  // Full names (First Last)
  { regex: /\b[A-Z][a-z]+ [A-Z][a-z]+\b/g, replacement: '[PERSON]' },
  // Email addresses
  { regex: /\b[A-Za-z0-9._%+-]+@[A-Za-z0-9.-]+\.[A-Z|a-z]{2,}\b/g, replacement: '[EMAIL]' },
  // Phone numbers (various formats)
  { regex: /\b(\+1[-.\s]?)?\(?\d{3}\)?[-.\s]?\d{3}[-.\s]?\d{4}\b/g, replacement: '[PHONE]' },
  // SSN
  { regex: /\b\d{3}-\d{2}-\d{4}\b/g, replacement: '[SSN]' },
  // Credit cards
  { regex: /\b\d{4}[-\s]?\d{4}[-\s]?\d{4}[-\s]?\d{4}\b/g, replacement: '[CARD]' },
  // Addresses
  { regex: /\b\d{1,5}\s+[\w\s]+(Street|St|Avenue|Ave|Road|Rd|Drive|Dr|Boulevard|Blvd|Lane|Ln|Way|Court|Ct|Circle|Cir)\b/gi, replacement: '[ADDRESS]' },
  // Order numbers (common patterns)
  { regex: /\b(ORD-|ORDER-|INV-|QUOTE-)\d{4,10}\b/gi, replacement: '[ORDER_ID]' },
  // Internal IDs (optional - removes but logs)
  { regex: /\b(id:|ID:|ref:|REF:)[A-Z0-9-_]+\b/gi, replacement: '[REF]' }
];

function cleanRecord(record) {
  const cleaned = { ...record.json };

  for (const key of Object.keys(cleaned)) {
    if (typeof cleaned[key] === 'string') {
      let value = cleaned[key];
      patterns.forEach(({ regex, replacement }) => {
        value = value.replace(regex, replacement);
      });
      cleaned[key] = value;
    }
  }

  // Log PII stats
  const originalStr = JSON.stringify(record.json);
  const cleanedStr = JSON.stringify(cleaned);
  if (originalStr !== cleanedStr) {
    cleaned._pii_cleaned = true;
  }

  return { json: cleaned };
}

const cleaned = records.map(cleanRecord);
const piiCount = cleaned.filter(d => d.json._pii_cleaned).length;
console.log(`PII cleaned in ${piiCount} of ${records.length} records`);

return cleaned;

// Final PII validation
const records = $input.all();

// Check for any remaining PII patterns
const remainingPII = [
  { name: 'Names', pattern: /\b[A-Z][a-z]+ [A-Z][a-z]+\b/g },
  { name: 'Emails', pattern: /\b[A-Za-z0-9._%+-]+@[A-Za-z0-9.-]+\.[A-Z|a-z]{2,}\b/g },
  { name: 'Phones', pattern: /\b\d{3}[-.\s]?\d{3}[-.\s]?\d{4}\b/g }
];

let flagged = 0;
const checked = records.map(record => {
  const checked = { ...record.json };
  let hasPII = false;

  for (const key of Object.keys(checked)) {
    if (typeof checked[key] === 'string') {
      for (const { name, pattern } of remainingPII) {
        const matches = checked[key].match(pattern);
        if (matches && !checked[key].includes('[REDACTED]') && !checked[key].includes('[PERSON]')) {
          hasPII = true;
          flagged++;
          break;
        }
      }
    }
    if (hasPII) break;
  }

  checked._pii_validated = !hasPII;
  return { json: checked };
});

console.log(`PII validation: ${flagged} potential issues found in ${records.length} records`);

// Return all records (PII is acceptable if redacted)
return checked;

// Convert records to instruction-following format
const records = $input.all();

function classifyCategory(record) {
  const r = record.json;
  const subject = (r.Subject || r.subject || '').toLowerCase();
  const category = (r.Category__c || r.category || '').toLowerCase();
  const desc = (r.Description || r.description || '').toLowerCase();
  const combined = subject + ' ' + category + ' ' + desc;

  if (combined.includes('quality') || combined.includes('defect') || combined.includes('warranty')) {
    return 'Quality - Warranty Claim';
  } else if (combined.includes('billing') || combined.includes('invoice') || combined.includes('payment')) {
    return 'Billing Inquiry';
  } else if (combined.includes('shipping') || combined.includes('delivery') || combined.includes('order')) {
    return 'Shipping - Order Status';
  } else if (combined.includes('return') || combined.includes('refund')) {
    return 'Returns - Refunds';
  } else {
    return 'General Inquiry';
  }
}

function determineEscalation(record) {
  const r = record.json;
  const level = r.EscalationLevel__c || r.escalationLevel || r.escalation_level || 'L1';
  return level.toString().toUpperCase();
}

function createInstruction(record) {
  const r = record.json;
  const subject = r.Subject || r.subject || '';
  const desc = r.Description || r.description || '';

  if (desc && desc.length > 10) {
    return `A customer reports: ${desc.substring(0, 300)}`;
  }
  return subject || 'Handle customer inquiry';
}

function createOutput(record) {
  const r = record.json;
  const category = classifyCategory(record);
  const escalation = determineEscalation(record);
  const resolution = r.Resolution || r.resolution || r.root_cause || '';
  const product = r.ProductFamily__c || r.product_line || r.ProductFamily || '';
  const customerTier = r.CustomerType__c || r.customer_tier || 'Standard';

  let response = `Category: ${category}
Escalation Level: ${escalation}
Product Line: ${product}
Customer Tier: ${customerTier}
`;

  if (resolution) {
    response += `\nKnown Resolution: ${resolution}`;
  }

  // Standard response protocols
  if (category.includes('Quality') || category.includes('Warranty')) {
    response += `\n\nResponse Protocol:\n1. Verify purchase date and warranty status\n2. Check lot trace for manufacturing date\n3. If under warranty: Issue return authorization\n4. Document: lot_number, warranty_status, resolution\n5. If out of warranty: Quote repair/replacement options`;
  } else if (category.includes('Billing')) {
    response += `\n\nResponse Protocol:\n1. Review account and invoice in question\n2. Verify charges against contract terms\n3. If error: Issue credit or adjustment\n4. If correct: Explain charges clearly\n5. Document in CRM`;
  } else {
    response += `\n\nResponse Protocol:\n1. Acknowledge customer concern\n2. Review relevant records\n3. Provide resolution or escalation path\n4. Document in system`;
  }

  return response;
}

const trainingData = records.map(record => {
  const r = record.json;
  return {
    json: {
      instruction: createInstruction(record),
      input: '',
      output: createOutput(record),
      _recordId: r._sourceId || r.Id || Math.random().toString(36)
    }
  };
});

console.log(`Formatted ${trainingData.length} training examples`);
return trainingData;

// Remove duplicate instructions
const records = $input.all();
const seen = new Set();
const unique = [];
let duplicates = 0;

for (const record of records) {
  const instruction = record.json.instruction;
  if (!seen.has(instruction)) {
    seen.add(instruction);
    unique.push(record);
  } else {
    duplicates++;
  }
}

console.log(`Deduplication: ${duplicates} duplicates removed, ${unique.length} unique records`);
return unique;

// Prepare Colab notebook configuration
const driveFile = $input.first().json;
const config = {
  clientName: 'ACME_CORP',
  clientSlug: 'acme',
  trainingDataFileId: driveFile.id || 'FILE_ID',
  modelOutputFolderId: 'NAMAKAN_MODELS_FOLDER_ID',
  version: '1',
  webhookUrl: 'YOUR_N8N_WEBHOOK_URL',
  timestamp: new Date().toISOString()
};

console.log('Colab configuration prepared');
console.log(JSON.stringify(config, null, 2));

return [{ json: config }];

